    .select('*, loyalty_programs(*, merchants(business_name))')
    .eq('id', qr_id)
    .eq('is_active', true)
    .single();

  if (!qrCode) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[var(--bg-base)]">
        <p className="text-[var(--error)]">QR code invalide ou expire.</p>
      </div>
    );
  }

  // Check if user is logged in
  const { data: { user } } = await supabase.auth.getUser();

  if (!user) {
    redirect(`/login?redirect=/scan/${qr_id}`);
  }

  return <ScanHandler qrCode={qrCode} userId={user.id} />;
}

'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';
import Card from '@/components/ui/Card';
import Button from '@/components/ui/Button';
import { toast } from 'sonner';
import { CheckCircle } from 'lucide-react';

export default function ScanHandler({ qrCode, userId }: { qrCode: any; userId: string }) {
  const router = useRouter();
  const [status, setStatus] = useState<'loading' | 'enrolled' | 'already'>('loading');

  useEffect(() => {
    const enroll = async () => {
      const supabase = createClient();
      const program = qrCode.loyalty_programs;

      // Check if already enrolled
      const { data: existing } = await supabase
        .from('customer_cards')
        .select('id')
        .eq('customer_id', userId)
        .eq('program_id', program.id)
        .single();

      if (existing) {
        setStatus('already');
        return;
      }

      // Ensure customer record exists
      await supabase.from('customers').upsert({ id: userId, email: '' }, { onConflict: 'id' });

      // Create card with welcome bonus
      const { error } = await supabase.from('customer_cards').insert({
        customer_id: userId,
        program_id: program.id,
        balance: program.welcome_bonus || 0,
      });

      if (error) { toast.error(error.message); return; }

      // Log welcome bonus transaction
      if (program.welcome_bonus > 0) {
        const { data: newCard } = await supabase
          .from('customer_cards')
          .select('id')
          .eq('customer_id', userId)
          .eq('program_id', program.id)
          .single();

        if (newCard) {
          await supabase.from('transactions').insert({
            card_id: newCard.id,
            merchant_id: program.merchant_id,
            type: 'earn',
            amount: program.welcome_bonus,
            source: 'qr',
          });
        }
      }

      setStatus('enrolled');
      toast.success(`+${program.welcome_bonus} bonus de bienvenue !`);
    };

    enroll();
  }, [qrCode, userId]);

  const program = qrCode.loyalty_programs;
  const merchant = program.merchants;

  return (
    <div className="min-h-screen flex items-center justify-center bg-[var(--bg-base)] p-4">
      <Card padding="lg" className="max-w-sm w-full text-center space-y-4 page-enter">
        <CheckCircle className="w-12 h-12 text-[var(--accent)] mx-auto" />
        <h2 className="text-xl font-bold text-[var(--text-primary)]">{merchant.business_name}</h2>
        <p className="text-[var(--text-secondary)]">
          {status === 'enrolled' && `Inscrit au programme "${program.name}" ! Bonus: +${program.welcome_bonus}`}
          {status === 'already' && `Vous etes deja inscrit au programme "${program.name}".`}
          {status === 'loading' && 'Inscription en cours...'}
        </p>
        <Button onClick={() => router.push('/customer')} className="w-full">Voir mes cartes</Button>
      </Card>
    </div>
  );
}
